#include <iostream>
#include <string>
#include <vector>
#include <fstream>
#include <sstream>
#include <cstdlib> // For system()
#include <cstdio>  // For popen, pclose, remove
#include <sys/wait.h> // For WIFSIGNALED, WTERMSIG

std::string exec_and_capture_robust(const std::string& cmd, const std::string& input_str, int timeout_sec = 2) {
    std::string result = "";
    std::string input_filename = "temp_input_driver.txt";
    std::ofstream input_file(input_filename);
    input_file << input_str;
    input_file.close();

    std::string full_cmd = "timeout " + std::to_string(timeout_sec) + "s " + cmd + " < " + input_filename;

    FILE* pipe = popen(full_cmd.c_str(), "r");
    if (!pipe) return "ERROR: Failed to open pipe.";
    char buffer[128];
    while (!feof(pipe)) {
        if (fgets(buffer, 128, pipe) != NULL)
            result += buffer;
    }
    int status = pclose(pipe);
    if (status != 0) {
        if (WIFSIGNALED(status) && WTERMSIG(status) == SIGTERM) {
             result += "\n[Driver Timeout Detected]";
        }
    }

    remove(input_filename.c_str());
    return result;
}

int main() {
    std::cout << "Driver: Compiling solution.cpp...\n";
    if (system("g++ solution.cpp -o solution_exec") != 0) {
        std::cerr << "Driver: Compilation of solution.cpp failed.\n";
        return 1;
    }

    // Test case for robustness: non-integer input leading to infinite loop
    std::string test_input = "abc\n";
    std::string expected_output_part = "Invalid input. Please enter an integer.\n[Driver Timeout Detected]"; // Expect timeout

    std::cout << "Driver: Running solution with input '" << test_input.substr(0, test_input.length()-1) << "' (with timeout)...\n";
    std::string actual_output = exec_and_capture_robust("./solution_exec", test_input, 2); // 2-second timeout

    std::cout << "Driver: --- Program Output ---\n" << actual_output;
    std::cout << "Driver: --- End Program Output ---\n";

    if (actual_output.find(expected_output_part) != std::string::npos) {
        std::cout << "Driver: Test case PASSED (output contains expected part and timeout).\n";
    } else {
        std::cout << "Driver: Test case FAILED.\n";
    }

    std::cout << "Driver: Cleaning up...\n";
    system("rm -f solution_exec");

    return 0;
}
